render.css:
.activity-list { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 12px; }
.activity-item { display: flex; justify-content: space-between; align-items: center; padding-bottom: 12px; border-bottom: 1px solid var(--ct-surface-2); }
.activity-item:last-child { border-bottom: none; padding-bottom: 0; }
.activity-info { display: flex; flex-direction: column; gap: 4px; }
.activity-title { font-size: 13px; font-weight: 500; color: var(--ct-text-primary); }
.activity-time { font-size: 11px; color: var(--ct-text-muted); font-variant-numeric: tabular-nums; }
.status-badge { font-size: 10px; font-weight: 600; padding: 3px 8px; border-radius: 999px; border: 1px solid; letter-spacing: 0.05em; }
.status-badge.nominal { color: var(--ct-text-primary); border-color: var(--ct-border-strong); }
.status-badge.warn { color: var(--ct-warning); border-color: var(--ct-warning); }
